                    maxMaxBufferLength: defaults.premiumFlag ? 60 : 20
                },
                type: defaults.platform,
                priority: 'hls',
                menu: {
                    relatedUrl: flashvars.related_url,
                    relatedData: newRelatedVideosData,
                    showOnPause: false,
                    slideout: {
                        enabled: defaults.relatedGridEnabled
                    }
                },
